import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as p,o as c,c as l,a as n,t as i,b as a,e as u,f as s}from"./app-a997f2cb.js";const d={},r=s('<h3 id="vue的特点是什么" tabindex="-1"><a class="header-anchor" href="#vue的特点是什么" aria-hidden="true">#</a> vue的特点是什么</h3><p>轻量级框架、双向数据绑定、组件化、虚拟 DOM</p><h4 id="mvvm模型" tabindex="-1"><a class="header-anchor" href="#mvvm模型" aria-hidden="true">#</a> MVVM模型</h4><ol><li>M：模型(<code>Model</code>)，数据模型，data中的数据;</li><li>V：视图(<code>View</code>)，模板代码; 负责数据的展示</li><li>VM：视图模型(<code>ViewModel</code>)：Vue实例，负责监听Model数据的改变 并且控制视图的更新</li><li>data中所有的属性，最后都出现在了vm身上;vm身上所有的属性及Vue原型上所有属性，在Vue模板中都可以直接使用。</li><li>MVVM：实现V与M的自动同步，当Model的属性改变时，不用再自己手动操作Dom元素，对应的View会自动改变。</li></ol><h3 id="vue指令相关" tabindex="-1"><a class="header-anchor" href="#vue指令相关" aria-hidden="true">#</a> Vue指令相关</h3><h4 id="内置指令" tabindex="-1"><a class="header-anchor" href="#内置指令" aria-hidden="true">#</a> 内置指令</h4>',6),k=n("li",null,"v-bind: 单向数据绑定",-1),v=n("li",null,[a("v-model：双向数据绑定，一般都应用在表单类元素上，比如"),n("code",null,"input、select")],-1),m=n("li",null,"v-if：条件渲染，控制数据是否存在",-1),h=n("li",null,"v-show：条件渲染，控制数据是否显示",-1),g=n("li",null,"v-html：向指定节点渲染html内容，比较危险，容易导致XSS注入攻击",-1),b=n("li",null,"v-text：向指定节点渲染文件",-1),f=n("li",null,"v-once:所在节点在初次动态渲染后，以后数据的改变不会引起v-once所在结构的更新",-1),x=n("li",null,"v-pre：可以利用它跳过没有指令的节点，加快编译",-1),q=s(`<h4 id="v-if-与-v-for" tabindex="-1"><a class="header-anchor" href="#v-if-与-v-for" aria-hidden="true">#</a> v-if 与 v-for</h4><p>不建议一起使用，因为解析时先解析 v-for 再解析 v-if。数据都渲染出来了才判断v-if, 可以写成计算属性的方式</p><h4 id="绑定样式" tabindex="-1"><a class="header-anchor" href="#绑定样式" aria-hidden="true">#</a> 绑定样式</h4><ol><li>class样式: 写法<code>:class=&quot;xxx&quot;</code>xxx可以是字符串、对象、数组。</li><li>style样式: 写法<code>:style=&quot;{fontSize: xxx}&quot;</code>其中xxx是动态值。</li></ol><h4 id="v-if、v-show、v-html" tabindex="-1"><a class="header-anchor" href="#v-if、v-show、v-html" aria-hidden="true">#</a> v-if、v-show、v-html</h4><ol><li>v-if条件不满足时不渲染此节点；v-show条件不满足时控制样式将对应节点隐藏；</li><li>v-if适用于在运行时不需要频繁切换条件的场景；v-show适用于需要非常频繁切换条件的场景，比如Tabs；</li><li>v-if原理：生成<code>vnode</code>的时候会忽略对应节点，<code>render</code>的时候就不会渲染；在编译过程中会被转化成三元表达式，条件不满足时不渲染此节点。</li><li>v-show原理：会生成<code>vnode</code>，<code>render</code>的时候也会渲染成真实节点。在编译过程中会被编译成指令，条件不满足时（<code>display:none</code>）控制样式将对应节点隐藏</li><li>v-html原理：会先移除节点下的所有节点，调用html方法，通过addProp添加<code>innerHTML</code>属性</li></ol><h4 id="v-model的原理" tabindex="-1"><a class="header-anchor" href="#v-model的原理" aria-hidden="true">#</a> v-model的原理？</h4><ol><li>本质是语法糖，动态绑定了input的value指向一个变量，并在触发input事件的时候动态把变量设置为目标值。写法是 <code>v-bind:value=&quot;message&quot;</code> <code>v-on:input=&quot;message= $event.target.value&quot;</code></li><li>v-model是<code>双向绑定，是单项数据流</code>。单项数据流就是子组件不能改变父组件传递给它的<code>prop</code>属性，推荐的做法是<code>$emit</code>通知父组件自行修改绑定的值。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// v-model用在普通标签上</span>
<span class="token operator">&lt;</span>input type<span class="token operator">=</span><span class="token string">&quot;text&quot;</span> v<span class="token operator">-</span>model<span class="token operator">=</span><span class="token string">&quot;username&quot;</span><span class="token operator">&gt;</span> <span class="token comment">//原生事件与自定义事件区别</span>
<span class="token operator">&lt;</span>input type<span class="token operator">=</span><span class="token string">&quot;text&quot;</span> <span class="token operator">:</span>value<span class="token operator">=</span><span class="token string">&quot;username&quot;</span> @input<span class="token operator">=</span><span class="token string">&quot;username = $event.target.value&quot;</span>
<span class="token comment">// v-model用在组件标签上 组件库的Input组件的实现！！</span>
<span class="token operator">&lt;</span>IviewInput type<span class="token operator">=</span><span class="token string">&quot;text&quot;</span> v<span class="token operator">-</span>model<span class="token operator">=</span><span class="token string">&quot;username&quot;</span><span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>IviewInput type<span class="token operator">=</span><span class="token string">&quot;text&quot;</span> <span class="token operator">:</span>modelValue<span class="token operator">=</span><span class="token string">&quot;username&quot;</span> @update<span class="token operator">:</span>modelValue<span class="token operator">=</span><span class="token string">&quot;username = $event&quot;</span><span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="自定义指令" tabindex="-1"><a class="header-anchor" href="#自定义指令" aria-hidden="true">#</a> 自定义指令</h4><ol><li>除了上述指令，还可以自定义指令</li><li>使用：① 局部定义：<code>new Vue({directives{指令名:配置对象/回调函数} }）</code>；② 全局指令：<code>Vue.directive(指令名,配置对象/回调函数)</code></li><li>配置对象中常用的3个回调：<code>.bind</code>：指令与元素成功绑定时调用；<code>.inserted</code>：指令所在元素被插入页面时调用；<code>.update</code>：指令所在模板结构被重新解析时调用。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 定义一个v-fbind指令，可以让其所绑定的input元素默认获取焦点。</span>
Vue<span class="token punctuation">.</span><span class="token function">directive</span><span class="token punctuation">(</span><span class="token string">&#39;fbind&#39;</span><span class="token punctuation">,</span><span class="token punctuation">{</span>
    <span class="token comment">//指令与元素成功绑定时（一上来）</span>
    <span class="token function">bind</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span>binding</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
            element<span class="token punctuation">.</span>value <span class="token operator">=</span> binding<span class="token punctuation">.</span>value
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token comment">//指令所在元素被插入页面时</span>
    <span class="token function">inserted</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span>binding</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
            element<span class="token punctuation">.</span><span class="token function">focus</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token comment">//指令所在的模板被重新解析时</span>
    <span class="token function">update</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span>binding</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
            element<span class="token punctuation">.</span>value <span class="token operator">=</span> binding<span class="token punctuation">.</span>value
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// 2 使用自定义指令，指令定义时不加v-，但使用时要加v-；</span>
<span class="token operator">&lt;</span>input type<span class="token operator">=</span><span class="token string">&quot;text&quot;</span> v<span class="token operator">-</span>fbind<span class="token operator">:</span>value<span class="token operator">=</span><span class="token string">&quot;n&quot;</span><span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="修饰符" tabindex="-1"><a class="header-anchor" href="#修饰符" aria-hidden="true">#</a> 修饰符</h3><h4 id="事件修饰符" tabindex="-1"><a class="header-anchor" href="#事件修饰符" aria-hidden="true">#</a> 事件修饰符</h4><ol><li>@click.prevent:阻止默认事件</li><li>@click.stop:阻止冒泡事件</li><li>@click.capture:使用事件的捕获模式</li><li>@click.once:事件只触发一次</li><li>@click.self:只有event.targent是当前操作的元素时才触发事件</li><li>@click.passive:事件的默认行为立即执行，无需等待事件回调执行完毕</li></ol><h4 id="键盘修饰符" tabindex="-1"><a class="header-anchor" href="#键盘修饰符" aria-hidden="true">#</a> 键盘修饰符</h4><ol><li>@keydown.enter 回车</li><li>@keyup.enter</li><li>@keydown.delete 删除</li></ol><h4 id="表单修饰符" tabindex="-1"><a class="header-anchor" href="#表单修饰符" aria-hidden="true">#</a> 表单修饰符</h4><ol><li>常见表单项 textarea checkbox radio select</li><li>v-model.number:将输入值转换为数值</li><li>v-model.trim：自动过滤用户输入的首尾空格</li><li>v-model.lazy：回车或者失去焦点的时候调用</li></ol><h3 id="computed与watch" tabindex="-1"><a class="header-anchor" href="#computed与watch" aria-hidden="true">#</a> computed与watch？</h3><h4 id="computed" tabindex="-1"><a class="header-anchor" href="#computed" aria-hidden="true">#</a> computed</h4><ol><li>是什么？计算属性，要用的属性不存在，要通过已有属性计算得来。</li><li>与methods实现相比，内部有缓存机制（复用），效率更高，调试方便。</li><li>原理：底层借助了<code>Objcet.defineproperty</code>方法提供的<code>getter</code>和<code>setter</code>。get函数什么时候执行？初次读取时会执行一次；当依赖的数据发生改变时会被再次调用。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token literal-property property">data</span><span class="token operator">:</span><span class="token punctuation">{</span>
    <span class="token literal-property property">firstName</span><span class="token operator">:</span><span class="token string">&#39;张&#39;</span><span class="token punctuation">,</span>
    <span class="token literal-property property">lastName</span><span class="token operator">:</span><span class="token string">&#39;三&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token literal-property property">computed</span><span class="token operator">:</span><span class="token punctuation">{</span>
    <span class="token function">fullName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;get被调用了&#39;</span><span class="token punctuation">)</span>
        <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>firstName <span class="token operator">+</span> <span class="token string">&#39;-&#39;</span> <span class="token operator">+</span> <span class="token keyword">this</span><span class="token punctuation">.</span>lastName
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="watch" tabindex="-1"><a class="header-anchor" href="#watch" aria-hidden="true">#</a> watch</h4><ol><li>是什么？监视属性watch，当被监视的属性变化时, 回调函数自动调用, 进行相关操作；</li><li>watch默认不监测对象内部值的改变，配置<code>deep:true</code>可以监测对象内部值改变（多层）；<code>immediate：true</code>让组件加载立即触发回调函数；</li><li>原理：使用Vue的原型方法<code>$watch</code>传入处理好的参数，进行创建用户Watcher</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token literal-property property">watch</span><span class="token operator">:</span><span class="token punctuation">{</span>
    <span class="token comment">//正常写法</span>
    <span class="token literal-property property">person</span><span class="token operator">:</span><span class="token punctuation">{</span>
        <span class="token literal-property property">immediate</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">//初始化时让handler调用一下</span>
        <span class="token literal-property property">deep</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">//深度监视</span>
        <span class="token function">handler</span><span class="token punctuation">(</span><span class="token parameter">newValue<span class="token punctuation">,</span>oldValue</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
            console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;被修改了&#39;</span><span class="token punctuation">,</span>newValue<span class="token punctuation">,</span>oldValue<span class="token punctuation">)</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token comment">//简写</span>
    <span class="token function">isHot</span><span class="token punctuation">(</span><span class="token parameter">newValue<span class="token punctuation">,</span>oldValue</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;isHot被修改了&#39;</span><span class="token punctuation">,</span>newValue<span class="token punctuation">,</span>oldValue<span class="token punctuation">,</span><span class="token keyword">this</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="computed与watch的区别" tabindex="-1"><a class="header-anchor" href="#computed与watch的区别" aria-hidden="true">#</a> computed与watch的区别?</h4><ol><li>computed不支持异步，支持缓存；watch支持异步，不支持缓存；</li><li>使用上：当值需要计算。并且依赖于其他属性可以利用computed的缓存属性，避免每次获取值时都要重新计算；当用于观测某个值的变化去完成一段复杂的业务逻辑或者执行异步，那么用watch。</li></ol><h3 id="vue的生命周期" tabindex="-1"><a class="header-anchor" href="#vue的生命周期" aria-hidden="true">#</a> vue的生命周期？</h3><ol><li><code>beforeCreate</code>：实例初始化之后，这时候<code>data method</code>不能访问</li><li><code>created</code>：实例已被创建，<code>data method watch computed</code>配置已经有了，但是没有<code>$el</code>，如果要与DOM交互，可以通过nextick来访问DOM</li><li><code>beforeMount</code>：在挂载之前调用，对DOM的操作不奏效</li><li><code>mounted</code>: DOM已挂载，数据完成双向绑定，可以开启定时器，网络请求，订阅事件、绑定自定义事件等</li><li><code>beforeUpdate</code>：数据更新之前调用，发生在虚拟dom重新渲染之前，这时候数据与页面还没有同步</li><li><code>updated</code>：数据更新后调用，当前阶段组件dom已完成更新</li><li><code>beforeDestroy</code>：实例销毁前调用，常用于清除定时器、解绑自定义事件等</li><li><code>destroyed</code>：实例销毁后调用，实例的东西会被解绑，子实例也被销毁</li></ol><h4 id="父子组件生命周期钩子函数执行顺序" tabindex="-1"><a class="header-anchor" href="#父子组件生命周期钩子函数执行顺序" aria-hidden="true">#</a> 父子组件生命周期钩子函数执行顺序？</h4><ol><li>加载渲染过程: 父 beforeCreate-&gt;父 created-&gt;父 beforeMount-&gt;子 beforeCreate-&gt;子 created-&gt;子 beforeMount-&gt;子 mounted-&gt;父 mounted</li><li>子组件更新过程：父 beforeUpdate-&gt;子 beforeUpdate-&gt;子 updated-&gt;父 updated</li><li>销毁过程：父 beforeDestroy-&gt;子 beforeDestroy-&gt;子 destroyed-&gt;父 destroyed</li></ol><h4 id="常用的生命周期钩子" tabindex="-1"><a class="header-anchor" href="#常用的生命周期钩子" aria-hidden="true">#</a> 常用的生命周期钩子：</h4><ol><li><code>mounted</code>: 一般是初始化操作，发送ajax请求、启动定时器、绑定自定义事件、订阅消息等。</li><li><code>beforeDestroy</code>: 一般是收尾工作，清除定时器、解绑自定义事件、取消订阅消息等。</li></ol><h3 id="组件通信" tabindex="-1"><a class="header-anchor" href="#组件通信" aria-hidden="true">#</a> 组件通信？</h3><ol><li><code>prop $emit</code>: 父组件通过<code>props</code>向子组件传递，子组件通过自定义事件，<code>$emit</code>触发事件来传递；</li><li><code>$refs $parent</code>:<code>$refs</code>用于父传子，父组件在使用子组件的时候设置ref，通过ref来获取数据；<code>$parent</code>用于子传父；</li><li><code>vuex</code>状态管理；</li><li>消息订阅与发布:提供数据<code>pubsub.publish(&#39;xxx&#39;,数据)</code>；接收数据<code>pubsub.subscribe(&#39;xxx&#39;,this.demo)</code>；</li><li><code>attrs listenters</code>:<code>$attrs</code>用于实现当前组件的父组件，向当前组件的子组件通信，可以实现祖孙通信；</li><li><code>provide inject</code>: 父组件通过<code>provide</code>提供变量，子组件通过<code>inject</code>注入变量。可以实现祖孙直接通信，在层级较深下，使用它来传值。</li></ol><h3 id="插槽" tabindex="-1"><a class="header-anchor" href="#插槽" aria-hidden="true">#</a> 插槽</h3><ol><li>是什么:通过插槽向组件内部指定位置传递内容，让这个组件在不同场景也能使用,比如布局组件，可以让用户扩展组件，更好的复用组件；</li><li>分类：默认插槽、具名插槽、作用域插槽</li><li>默认插槽: 子组件使用<code>&lt;slot/&gt;</code>标签即可渲染父组件传下来的插槽内容；</li><li>具名插槽: 有时候可能需要指定多个插槽，那么需要名字来区分。子组件用name属性来表示插槽的名字，写法是<code>&lt;slot name=&quot;s1&quot;/&gt;</code> 父组件需要通过templates标签绑定<code>v-slot:name</code>的属性，来指定传入哪个插槽里。</li></ol><div class="language-vue line-numbers-mode" data-ext="vue"><pre class="language-vue"><code>// 父组件中：
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>Category</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name">slot</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>center<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>html结构1<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name"><span class="token namespace">v-slot:</span>footer</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>html结构2<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>Category</span><span class="token punctuation">&gt;</span></span>

// 子组件中：
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- 定义插槽 --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>slot</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>center<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>插槽默认内容...<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>slot</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>slot</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>footer<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>插槽默认内容...<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>slot</span><span class="token punctuation">&gt;</span></span>
 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="5"><li>作用域插槽：子组件去维护自己的数据与结构，界面结构由父组件决定。子传父<code>&lt;slot :game=&quot;games&quot; /&gt;</code>，父接收是templates标签绑定<code>slot-scope=&quot;scopeData&quot;</code>的属性。</li></ol><div class="language-vue line-numbers-mode" data-ext="vue"><pre class="language-vue"><code>// 父组件中：
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>Category</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span> <span class="token attr-name">slot-scope</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>scopeData<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
       <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h4</span> <span class="token attr-name">v-for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>g in scopeData.games<span class="token punctuation">&quot;</span></span> <span class="token attr-name">:key</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>g<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>{{g}}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h4</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>Category</span><span class="token punctuation">&gt;</span></span>

// 子组件中：
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>
       <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>slot</span> <span class="token attr-name">:games</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>games<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>slot</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">name</span><span class="token operator">:</span><span class="token string">&#39;Category&#39;</span><span class="token punctuation">,</span>
    <span class="token function">data</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">//数据在子组件自身</span>
        <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">games</span><span class="token operator">:</span><span class="token punctuation">[</span><span class="token string">&#39;红色警戒&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;穿越火线&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;劲舞团&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;超级玛丽&#39;</span><span class="token punctuation">]</span> <span class="token punctuation">}</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="vuex是什么" tabindex="-1"><a class="header-anchor" href="#vuex是什么" aria-hidden="true">#</a> Vuex是什么？</h3><ol><li>是什么：状态管理库，对vue中多个组件的共享状态进行集中式的管理，是一种组件间通信的方式，且适用于任意组件间通信。</li><li>主要由<code>State、Mutations、Actions、Getter、Module</code>构成。它在全局拥有一个<code>State</code>存放数据，当组件要修改数据时候，必须通过<code>Mutation</code>进行。而有异步操作的时候，就需要走<code>Action</code>，但<code>Action</code>也是无法直接修改<code>State</code>，还得通过<code>Mutation</code>。</li><li>State: 定义了应用状态的数据结构，可以在这里设置默认的初始状态；</li><li>Getter: 对state数据的一个过滤和加工。getters就像计算属性一样，getter返回值会根据它的依赖被缓存起来</li><li>Mutations：修改state的数据，是唯一更新store中状态的方法，只能进行同步操作<code>this.store.commit(&quot;mutations中方法名&quot;, 数据)</code></li><li>Actions: 响应组件中用户的动作，可以请求接口，通过<code>this.store.dispatch(&quot;actions中方法名&quot;,数据)</code>触发</li><li>Module: 允许将单一的store拆分成多个store，并同时保存在单一的状态树中。</li><li>Vuex和localStorage的区别？① <code>localstorage</code>则以文件的方式存储在本地，数据持久存储。只能存储字符串类型的数据，存储对象需要JSON的<code>stringify</code>和<code>parse</code>方法进行处理；② <code>Vuex</code>存储在内存中,一刷新数据就丢失，可以使用<code>vuex-persist</code>插件。</li></ol><h3 id="vue-router" tabindex="-1"><a class="header-anchor" href="#vue-router" aria-hidden="true">#</a> vue-router</h3><ol><li>为什么需要路由？ 因为用Vue做的都是单页应用,它只有一个完整的页面，在加载页面时，不会加载整个页面，而是只更新某个指定的容器中内容。它在更新视图而不重新请求页面。</li><li><code>param</code>配置路由格式：<code>/router/:id</code>，传递后形成的路径：<code>/router/123</code></li></ol><blockquote><p>param+to字符串方式：<code>&lt;router-link :to=&quot;&#39;/user/&#39;+userId&quot; replace&gt;用户&lt;/router-link&gt;</code><br> param+to对象方式：<code>&lt;router-link :to=&quot;{ name: &#39;users&#39;, params: { uname: wade }}&quot;&gt;按钮&lt;/router-link&gt;</code><br> router跳转：<code>this.$router.push({name:&#39;users&#39;,params:{uname:wade}})</code><br> 参数获取：通过 $route.params.userid\`获取传递的值</p></blockquote><ol start="3"><li><code>query</code>配置路由格式：<code>/router</code>，传递后形成的路径：<code>/route?id=123</code></li></ol><blockquote><p>query+to字符串方式：<code>&lt;router-link :to=&quot;/user?uname=james&quot;&gt;跳转&lt;/router-link&gt;</code><br> query+to对象方式：<code>&lt;router-link :to=&quot;{ path: &#39;/user&#39;, query: { uname:james }}&quot;&gt;按钮&lt;/router-link&gt;</code><br> router跳转：<code>this.$router.push({ path: &#39;/user&#39;, query:{ uname:james }})</code><br> 参数获取：通过 $route.query.userid 获取传递的值</p></blockquote><ol start="4"><li><code>$route</code>：路由信息对象，每个组件都有自己的<code>$route</code>属性，里面存储着自己的路由信息如：<code>path query params hash name</code>等</li><li><code>$router</code>:路由实例，整个应用只有一个<code>router</code>,用法：<code>this.$router.go(); router.afterEach; this.$router.push({...})</code></li><li>缓存路由组件：用<code>keep-alive</code>来缓存页面，当组件在<code>keep-alive</code>内被切换时组件的<code>activated、deactivated</code>这两个生命周期钩子函数会被执行。</li><li>路由守卫：对路由进行权限控制。分类：全局守卫、独享守卫、组件内守卫;</li></ol><blockquote><p>a. 全局守卫: router.beforeEach()前置守卫； beforeResolved():解析守卫；brforeRouteEnter()之后调用；router.afterEach()后置守卫；<br> b. 独享守卫：beforeEnter()为某些路由单独配置守卫；<br> c. 组件内守卫：beforeRouteEnter()进入组件前触发； beforeRouteLeave()离开组件被调用</p></blockquote><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//全局前置守卫：初始化时执行、每次路由切换前执行</span>
router<span class="token punctuation">.</span><span class="token function">beforeEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">to<span class="token punctuation">,</span>from<span class="token punctuation">,</span>next</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;beforeEach&#39;</span><span class="token punctuation">,</span>to<span class="token punctuation">,</span>from<span class="token punctuation">)</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>to<span class="token punctuation">.</span>meta<span class="token punctuation">.</span>isAuth<span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token comment">//判断当前路由是否需要进行权限控制</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span><span class="token operator">...</span><span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token comment">//权限控制的具体规则</span>
           <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">//放行</span>
        <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
           <span class="token function">alert</span><span class="token punctuation">(</span><span class="token string">&#39;暂无权限查看&#39;</span><span class="token punctuation">)</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">//放行</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="keep-alive-具体缓存的是什么" tabindex="-1"><a class="header-anchor" href="#keep-alive-具体缓存的是什么" aria-hidden="true">#</a> keep-alive，具体缓存的是什么？</h3><ol><li>是什么：不让组件重新加载，直接保留在内存中。它有<code>include exclude max</code>属性，<code>include</code>是匹配名称的组件才会被缓存；<code>exclude</code>是匹配名称的组件不会被缓存；max 数字，最多可以缓存多少组件实例。</li><li>设置<code>keep-alive</code>缓存的组件，会多出两个生命周期钩子（<code>activated deactivated</code>)。<code>activated</code>路由组件被激活时触发；<code>deactivated</code>路由组件失活时触发；</li><li>首次进入时：beforeRouteEnter - beforeCreate - created - beforeMount - mounted - activated ...-beforeRouteLeave - deactivated</li><li>再次进入时：beforeRouteEnter - activated ...-beforeRouteLeave - deactivated</li></ol><div class="language-vue line-numbers-mode" data-ext="vue"><pre class="language-vue"><code>   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>keep-alive</span> <span class="token attr-name">include</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>News<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span> 
       <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>router-view</span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>router-view</span><span class="token punctuation">&gt;</span></span>
   <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>keep-alive</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="什么是-mixin" tabindex="-1"><a class="header-anchor" href="#什么是-mixin" aria-hidden="true">#</a> 什么是 mixin</h3><ol><li>是什么:是一个js对象，包含我们组件中任意功能选项，如<code>data、components、methods、created、computed</code>等等；可以把组件的公共逻辑提取出来传入mixins选项中。当组件使用 mixins对象时，mixins对象的选项都将被混入该组件本身的选项中来，目的是减少代码冗余度，方便后续维护;</li><li>选项合并：mixin与组件的配置合并后，命名有冲突了分为两种情况；① 生命周期函数：生命周期函数合并后执行顺序是先执行mixin中的，后执行组件的；② data、方法：组件中的data数据、methods会覆盖mixin中数据</li><li>用法：<code>import { mixins } from &quot;./mixin/index&quot;;mixins:[&#39;xxx&#39;]</code></li><li>优点：提高代码复用性，维护方便</li><li>缺点：变量来源不明确，不利于阅读；多mixin 可能会造成命名冲突；mixin 和组件可能出现多对多的关系，复杂度较高</li><li><code>mixin与Vuex</code>区别：不同组件中的Mixin是相互独立的，Mixin中的数据和方法都是独立的，组件之间使用后是互相不影响的。Vuex则不一样，它是公共状态管理，在一个组件中更改了Vuex中的某个数据，其它所有引用了Vuex中该数据的组件也会跟着变化</li></ol><h3 id="动态、异步组件" tabindex="-1"><a class="header-anchor" href="#动态、异步组件" aria-hidden="true">#</a> 动态、异步组件</h3><ol><li>动态组件是什么：需要根据数据，动态渲染的场景，组件类型不确定使用。</li><li>动态组件使用：<code>&lt;div v-for=&quot;(val, key) in newsData&quot; :key=&quot;key&quot;&gt;&lt;component :is=&quot;val.type&#39;/&gt;&lt;/div&gt;</code></li><li>异步组件是什么：使用<code>import()</code>函数按需加载，去异步加载大组件，是常用的性能优化。</li><li>异步组件使用：<code>components:{FormDemo: () =&gt; import(&#39;@/BaseUse/FormDemo&quot;)}</code></li></ol><h3 id="对ssr的理解" tabindex="-1"><a class="header-anchor" href="#对ssr的理解" aria-hidden="true">#</a> 对SSR的理解</h3><ol><li>SSR 也就是服务端渲染，也就是在服务器端将Vue组件渲染为HTML字符串，然后再把HTML直接返回给客户端。</li><li>优点：SSR 有着更好的SEO,首屏加载速度更快</li></ol><h3 id="链接" tabindex="-1"><a class="header-anchor" href="#链接" aria-hidden="true">#</a> 链接</h3>`,61),y={href:"https://www.bilibili.com/video/BV1Zy4y1K7SH/?spm_id_from=333.337.search-card.all.click&vd_source=a3aec2a1dd5f478da3517872d0c61c5c",target:"_blank",rel:"noopener noreferrer"};function w(e,V){const t=p("ExternalLinkIcon");return c(),l("div",null,[r,n("ol",null,[k,v,m,h,g,b,f,n("li",null,"v-clock：用css配合v-cloak可以解决网速慢时页面展示出"+i(e.xxx)+"的问题",1),x]),q,n("p",null,[n("a",y,[a("尚硅谷Vue2.0+Vue3.0全套教程"),u(t)])])])}const j=o(d,[["render",w],["__file","vue2核心语法.html.vue"]]);export{j as default};
